Here is a clean v7 implementation. The `switchMap` cancels any in-flight `searchProducts$` call when the user types a new character — `mergeMap` would race.

```ts
import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, filter, switchMap } from 'rxjs/operators';

interface Product {
  id: string;
  title: string;
  priceCents: number;
}

declare function searchProducts$(q: string): Observable<Product[]>;

export function productTypeahead(
  keystroke$: Observable<string>
): Observable<Product[]> {
  return keystroke$.pipe(
    debounceTime(300),
    distinctUntilChanged(),
    filter((q: string) => q.trim().length >= 2),
    switchMap((q: string) => searchProducts$(q))
  );
}
```

```ts
import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, filter, switchMap } from 'rxjs/operators';

interface Repo {
  id: number;
  fullName: string;
  stars: number;
}

declare function fetchRepos$(q: string): Observable<Repo[]>;

export function repoAutocomplete(
  query$: Observable<string>
): Observable<Repo[]> {
  return query$.pipe(
    debounceTime(250),
    distinctUntilChanged(),
    filter((q: string) => q.length > 0),
    switchMap((q: string) => fetchRepos$(q))
  );
}
```

`switchMap` is essential — it unsubscribes from the previous `fetchRepos$` when the user types another character, so stale results never overwrite fresher ones.

