Convert this legacy RxJS (pre-v7, patched operator style) typeahead to v7:

```ts
import { Observable } from 'rxjs/Rx';
import 'rxjs/add/operator/debounceTime';
import 'rxjs/add/operator/distinctUntilChanged';
import 'rxjs/add/operator/switchMap';
import 'rxjs/add/operator/do';

declare function searchApi(q: string): Observable<string[]>;

function oldTypeahead(input$: Observable<string>): Observable<string[]> {
  return input$
    .debounceTime(300)
    .distinctUntilChanged()
    .do(q => console.log('q=', q))
    .switchMap(q => searchApi(q));
}
```

```ts
import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap, tap } from 'rxjs/operators';

declare function searchApi(q: string): Observable<string[]>;

export function typeahead(input$: Observable<string>): Observable<string[]> {
  return input$.pipe(
    debounceTime(300),
    distinctUntilChanged(),
    tap((q: string) => console.log('q=', q)),
    switchMap((q: string) => searchApi(q))
  );
}
```

Key deltas: import from `'rxjs'` not `'rxjs/Rx'`; operators are pipeable (no more prototype-patching via `rxjs/add/operator/*`); `.do(...)` is now `tap(...)`; chain via `.pipe(op1, op2, ...)` instead of method-per-operator.

Convert this v4-ish chained typeahead to RxJS v7 pipeable operators:

```ts
