declare function findUsers(q: string): Observable<{ id: string }[]>;

function userSearch(input$: Observable<string>) {
  return input$
    .debounceTime(250)
    .distinctUntilChanged()
    .filter(q => q.length > 1)
    .switchMap(q => findUsers(q));
}
```

```ts
import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, filter, switchMap } from 'rxjs/operators';

