The `as any` escape hatch disappears in v7 because all operators are imported as standalone functions and threaded through `pipe` — TypeScript can now infer the whole chain.

```ts
import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap, tap } from 'rxjs/operators';

interface Tag {
  id: string;
  name: string;
}

declare function fetchTags(q: string): Observable<Tag[]>;
declare function log(q: string): void;
declare const input$: Observable<string>;

export const tagSearch$: Observable<Tag[]> = input$.pipe(
  debounceTime(300),
  distinctUntilChanged(),
  tap((q: string) => log(q)),
