```ts
import { Observable, concat, of } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap } from 'rxjs/operators';

type SearchState<T> =
  | { status: 'loading'; query: string }
  | { status: 'done'; query: string; results: T[] };

declare function search$(q: string): Observable<string[]>;

export const hits$ = (
  q$: Observable<string>
): Observable<SearchState<string>> =>
  q$.pipe(
    debounceTime(300),
    distinctUntilChanged(),
    switchMap((q: string) =>
      concat(
        of<SearchState<string>>({ status: 'loading', query: q }),
        search$(q).pipe(
          // one map on results per inner observable
          switchMap((results: string[]) =>
            of<SearchState<string>>({ status: 'done', query: q, results })
          )
        )
      )
    )
  );
```

Using `concat(of(loading), search$)` inside the outer `switchMap` means every new keystroke emits a fresh `loading` first, and the previous inner (including any stale `loading`) is cancelled.

Add a cancel-on-blur signal to this document-search typeahead (pass it a `blur$: Observable<void>` that clears results):

```ts
import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap } from 'rxjs/operators';

declare function findDocs$(q: string): Observable<Doc[]>;
interface Doc { id: string; title: string }

export const docs$ = (q$: Observable<string>) =>
