```

```ts
import { Observable, merge, of } from 'rxjs';
import { debounceTime, distinctUntilChanged, map, switchMap } from 'rxjs/operators';

interface Doc {
  id: string;
  title: string;
}

declare function findDocs$(q: string): Observable<Doc[]>;

export const docs$ = (
  q$: Observable<string>,
  blur$: Observable<void>
): Observable<Doc[]> => {
  const clear$: Observable<Doc[]> = blur$.pipe(map((): Doc[] => []));
  const search$: Observable<Doc[]> = q$.pipe(
    debounceTime(300),
    distinctUntilChanged(),
    switchMap((q: string) => (q ? findDocs$(q) : of<Doc[]>([])))
  );
  return merge(search$, clear$);
};
```

`merge` lets `blur$` emit an empty-results value at any time; `switchMap` already cancels the in-flight request on a new query, so losing focus mid-request just means the response is discarded when it arrives (the subscriber has already unsubscribed).

