```ts
import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap } from 'rxjs/operators';

interface Recipe {
  id: string;
  title: string;
  cuisine: 'italian' | 'japanese' | 'mexican' | 'other';
}

declare function searchByTag$(tag: string): Observable<Recipe[]>;

export function recipeTagSearch(
  tag$: Observable<string>
