Every callback's parameter and return type is annotated — TypeScript could infer most of it, but the explicit annotations make the contract obvious to readers and stop `noImplicitAny` surprises if the shape of the upstream changes.

```ts
import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, map, switchMap } from 'rxjs/operators';

type LookupResult =
  | { status: 'found'; word: string; definitions: string[] }
  | { status: 'missing'; word: string };

declare function fetchDefinitions$(word: string): Observable<string[]>;

export function dictionaryLookup(
  term$: Observable<string>
): Observable<LookupResult> {
  return term$.pipe(
    debounceTime(300),
    distinctUntilChanged(),
    switchMap((word: string): Observable<LookupResult> =>
      fetchDefinitions$(word).pipe(
        map((defs: string[]): LookupResult =>
          defs.length === 0
            ? { status: 'missing', word }
            : { status: 'found', word, definitions: defs }
        )
      )
    )
  );
}
```

The inner `map` discriminates on `defs.length` so downstream consumers can narrow via `result.status` without optional-chaining.

```ts
