import { debounceTime, distinctUntilChanged, switchMap } from 'rxjs/operators';

declare function find$(q: string): Observable<string[]>;

export const run = (q$: Observable<string>) =>
  q$.pipe(
    debounceTime(300),
    distinctUntilChanged(),
    switchMap(q => find$(q))
  );
```

```ts
import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap, tap } from 'rxjs/operators';

declare function find$(q: string): Observable<string[]>;

export const run = (
  q$: Observable<string>
): Observable<string[]> =>
  q$.pipe(
    debounceTime(300),
    distinctUntilChanged(),
    tap({
      next: (q: string) => console.log('query ->', q),
      error: (err: unknown) => console.error('query stream errored:', err),
    }),
    switchMap((q: string) => find$(q))
  );
```

Object-form `tap` lets you observe `next`/`error`/`complete` independently; the old positional `tap(next, error, complete)` form is deprecated in v7.

The pipeline has three operators stacked:

- `debounceTime(ms)` waits for a pause in emissions, so you don't fire a request on every keystroke.
- `distinctUntilChanged()` drops re-emissions with the same value — prevents re-querying when the debounced value happens to equal the previous one.
- `switchMap(project)` subscribes to the inner observable and, crucially, *unsubscribes* the previous inner observable when a new outer value arrives. That's what makes stale in-flight requests get cancelled.

```ts
import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap } from 'rxjs/operators';

interface Place {
  id: string;
  name: string;
  lat: number;
  lon: number;
}

declare function searchPlaces$(q: string): Observable<Place[]>;

export function placeTypeahead(
  query$: Observable<string>
): Observable<Place[]> {
  return query$.pipe(
    debounceTime(300),
    distinctUntilChanged(),
    switchMap((q: string) => searchPlaces$(q))
  );
}
```

Using `mergeMap` here would be the classic bug — responses can arrive out of order and overwrite fresher results.

The three-operator stack decouples *when* you search (after the user pauses) from *what* you search for (unique values only) from *how* you handle overlapping async requests (always keep the latest). Put another way: `debounceTime` smooths the burst of events, `distinctUntilChanged` collapses no-op re-emissions, and `switchMap` enforces "one inner observable at a time — newer wins."

```ts
import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap } from 'rxjs/operators';

interface Employee {
  id: string;
  name: string;
  department: string;
}

declare function filterEmployees$(q: string): Observable<Employee[]>;

export function employeeLiveFilter(
  term$: Observable<string>
): Observable<Employee[]> {
  return term$.pipe(
    debounceTime(200),
    distinctUntilChanged(),
    switchMap((q: string) => filterEmployees$(q))
  );
}
```

`switchMap` subscribes to whatever inner observable its projection function returns. When the outer observable emits a new value while the previous inner is still active, `switchMap` calls `unsubscribe` on that previous inner subscription before subscribing to the new one. For a network-backed inner observable that hooks into `AbortController`, that unsubscribe aborts the HTTP request. Net effect: only the most-recent inner observable ever emits to the downstream.

