The `map` strips `#` and lowercases before `distinctUntilChanged` so `"#Foo"`, `"foo"`, and `"FOO"` all collapse to a single request.

```ts
import { Observable, of } from 'rxjs';
import { debounceTime, distinctUntilChanged, switchMap } from 'rxjs/operators';

interface Todo {
  id: string;
  text: string;
  done: boolean;
}

export function todoLiveFilter(
  todos: readonly Todo[],
  term$: Observable<string>
): Observable<Todo[]> {
  return term$.pipe(
    debounceTime(150),
    distinctUntilChanged(),
    switchMap((q: string): Observable<Todo[]> => {
      const needle = q.trim().toLowerCase();
      const out: Todo[] = needle
        ? todos.filter((t: Todo) => t.text.toLowerCase().includes(needle))
        : [...todos];
      return of(out);
    })
  );
}
```

Wrapping the sync filter in `of(...)` keeps the shape `Observable<Todo[]>` so a future swap to `fetchFiltered$` is a drop-in change; the outer stream semantics don't move.

